productChangeStatusInvalidLiteral.query:
mutation ProductChangeStatusInvalidStatusLiteral {
  productChangeStatus(productId: "gid://shopify/Product/999999999999999", status: ENABLED) {
    product {
      id
      status
      updatedAt
    }
    userErrors {
      field
      message
    }
  }
}

productChangeStatusInvalidVariable.query:
mutation ProductChangeStatusInvalidStatusVariable($productId: ID!, $status: ProductStatus!) {
  productChangeStatus(productId: $productId, status: $status) {
    product {
      id
      status
      updatedAt
    }
    userErrors {
      field
      message
    }
  }
}

